const data      = $input.first().json;
const clientCtx = $('Build Gemini Prompt').first().json;

const clientId    = data.clientId    || clientCtx.clientId    || '';
const clientName  = data.clientName  || clientCtx.clientName  || '';
const clientEmail = data.clientEmail || clientCtx.clientEmail || '';
const clientPhone = data.clientPhone || clientCtx.clientPhone || '';
const planType    = data.planType    || clientCtx.planType    || '';
const goal        = data.goal        || clientCtx.goal        || '';
const age         = data.age         || clientCtx.age         || '';
const gender      = data.gender      || clientCtx.gender      || '';
const isDiet      = data.isDiet;

return [{ json: {
  clientId,
  clientName,
  clientEmail,
  clientPhone,
  goal,
  age,
  gender,
  planType,
  isDiet,
  workoutJson:  isDiet ? null : data.workoutJson,
  dietHtml:     isDiet ? data.planHtml : null,
  generatedAt:  new Date().toISOString()
}}];

const allItems  = $input.all();
const base      = allItems[0].json;
const clientCtx = $('Build Gemini Prompt').first().json;

if (!base.exerciseMode) {
  return [{ json: {
    ...base,
    clientId:    clientCtx.clientId,
    clientName:  clientCtx.clientName,
    clientEmail: clientCtx.clientEmail,
    clientPhone: clientCtx.clientPhone,
    planType:    clientCtx.planType
  }}];
}

const wj = base.workoutJson;
const dayMap = new Map();
for (const item of allItems) {
  const d = item.json;
  if (!dayMap.has(d.day)) dayMap.set(d.day, { day: d.day, muscle: d.muscle, exercises: [] });
  dayMap.get(d.day).exercises.push({
    name: d.exerciseName, sets: d.sets, reps: d.reps,
    setsReps: d.setsReps,
    videoId: d.videoId, videoUrl: d.videoUrl,
    videoTitle: d.videoTitle, channelName: d.channelName,
    durationSeconds: d.durationSeconds,
    isPreferredShort: d.isPreferredShort,
    isShortCandidate: d.isShortCandidate,
    videoFallback: d.videoFallback,
    videoSearchQuery: d.videoSearchQuery,
    thumb: d.thumb
  });
}

const sourceDays = Array.isArray(wj?.days) ? wj.days : [];
const enrichedDays = sourceDays.map(day => {
  if (dayMap.has(day.day)) return dayMap.get(day.day);
  return { day: day.day, muscle: day.muscle || 'Rest', exercises: [] };
});
const enrichedWorkoutJson = {
  greeting:     wj ? wj.greeting     : '',
  overview:     wj ? wj.overview     : '',
  warmup:       wj ? wj.warmup       : [],
  cooldown:     wj ? wj.cooldown     : [],
  recoveryTips: wj ? wj.recoveryTips : [],
  days: enrichedDays
};

return [{ json: {
  isDiet:       false,
  workoutJson:  enrichedWorkoutJson,
  planHtml:     null,
  clientId:     clientCtx.clientId,
  clientName:   clientCtx.clientName,
  clientEmail:  clientCtx.clientEmail,
  clientPhone:  clientCtx.clientPhone,
  planType:     clientCtx.planType
}}];

const ytItems = $input.all();
const exItems = $('Extract Exercises').all();
const firstExtracted = exItems[0]?.json || {};

if (firstExtracted.exerciseMode === false) {
  return exItems.map(item => ({ json: item.json }));
}

const clientCtx = $('Build Gemini Prompt').first().json;
const output = [];

function parseIsoDuration(value) {
  const match = String(value || '').match(/^PT(?:(\d+)H)?(?:(\d+)M)?(?:(\d+)S)?$/);
  if (!match) return null;
  return (Number(match[1] || 0) * 3600) + (Number(match[2] || 0) * 60) + Number(match[3] || 0);
}

function words(value) {
  return String(value || '')
    .toLowerCase()
    .replace(/[^a-z0-9\s]/g, ' ')
    .split(/\s+/)
    .filter(word => word.length > 2 && !['with', 'the', 'and', 'for', 'how', 'shorts', 'exercise', 'proper', 'form'].includes(word));
}

function scoreVideo(video, exerciseName) {
  const title = String(video.snippet?.title || '').toLowerCase();
  const channel = String(video.snippet?.channelTitle || '').toLowerCase();
  const duration = parseIsoDuration(video.contentDetails?.duration) || 9999;
  const exWords = words(exerciseName);
  const titleHits = exWords.filter(word => title.includes(word)).length;
  const allWordsHit = exWords.length > 0 && titleHits === exWords.length;
  let score = 0;
  if (duration <= 30) score += 140;
  else if (duration <= 60) score += 95;
  else if (duration <= 120) score += 15;
  score += titleHits * 25;
  if (allWordsHit) score += 45;
  if (title.includes('short') || title.includes('#shorts')) score += 18;
  if (title.includes('proper') || title.includes('form') || title.includes('tutorial')) score += 16;
  if (title.includes('mistake') || title.includes('compilation') || title.includes('funny')) score -= 45;
  if (channel.includes('official') || channel.includes('fitness') || channel.includes('coach')) score += 6;
  score -= Math.max(0, duration - 30) / 4;
  return score;
}

for (let i = 0; i < ytItems.length; i++) {
  const ytResp = ytItems[i].json;
  const exCtx = exItems[i] ? exItems[i].json : {};
  const videos = (ytResp.items || [])
    .filter(video => video.id && video.status?.embeddable !== false)
    .map(video => ({ ...video, durationSeconds: parseIsoDuration(video.contentDetails?.duration) }));
  const sorted = videos.sort((a, b) => scoreVideo(b, exCtx.exerciseName) - scoreVideo(a, exCtx.exerciseName));
  const chosen = sorted.find(video => video.durationSeconds && video.durationSeconds <= 30)
    || sorted.find(video => video.durationSeconds && video.durationSeconds <= 60)
    || sorted[0]
    || null;

  let videoId = null;
  let videoUrl = null;
  let videoTitle = null;
  let channelName = null;
  let thumb = null;
  let durationSeconds = null;
  let isShortCandidate = false;
  let isPreferredShort = false;
  let videoFallback = true;
  if (chosen) {
    videoId = chosen.id;
    videoUrl = 'https://www.youtube.com/watch?v=' + videoId;
    videoTitle = chosen.snippet?.title || null;
    channelName = chosen.snippet?.channelTitle || null;
    const thumbnails = chosen.snippet?.thumbnails || {};
    thumb = (thumbnails.medium || thumbnails.high || thumbnails.default || {}).url || null;
    durationSeconds = chosen.durationSeconds || null;
    isPreferredShort = Boolean(durationSeconds && durationSeconds <= 30);
    isShortCandidate = Boolean(durationSeconds && durationSeconds <= 60);
    videoFallback = !isShortCandidate;
  }

  output.push({ json: {
    exerciseMode: true,
    exerciseName: exCtx.exerciseName || '',
    sets: exCtx.sets || '3',
    reps: exCtx.reps || '10',
    setsReps: exCtx.setsReps || '3 x ' + (exCtx.reps || '10'),
    day: exCtx.day || '',
    muscle: exCtx.muscle || '',
    videoId,
    videoUrl,
    videoTitle,
    channelName,
    durationSeconds,
    isShortCandidate,
    isPreferredShort,
    videoFallback,
    videoSearchQuery: exCtx.ytQuery || '',
    thumb,
    workoutJson: exCtx.workoutJson || null,
    clientId: clientCtx.clientId,
    clientName: clientCtx.clientName,
    clientEmail: clientCtx.clientEmail,
    clientPhone: clientCtx.clientPhone,
    planType: clientCtx.planType,
    goal: clientCtx.goal,
    isDiet: false
  }});
}
return output;

const data = $input.first().json;
const clientCtx = $('Build Gemini Prompt').first().json;

if (data.isDiet) {
  return [{ json: { ...data, exerciseMode: false, ytQuery: 'healthy diet nutrition meal plan' } }];
}

const wj = data.workoutJson;
if (!wj || !wj.days || !wj.days.length) {
  return [{ json: { ...data, exerciseMode: false, ytQuery: 'fitness workout form' } }];
}

const items = [];
for (const day of wj.days) {
  for (const ex of (day.exercises || [])) {
    const exName = typeof ex === 'string' ? ex : (ex.name || '');
    if (!exName) continue;
    const exSets = ex.sets ? String(ex.sets) : '3';
    const exReps = ex.reps ? String(ex.reps) : '10';
    const context = [
      clientCtx.gymAccess,
      clientCtx.goal,
      clientCtx.focusArea,
      clientCtx.injuries && clientCtx.injuries !== 'None' ? clientCtx.injuries : '',
      'exercise form',
      '30 seconds',
      '#shorts'
    ].filter(Boolean).join(' ');
    items.push({ json: {
      exerciseMode: true,
      exerciseName: exName,
      sets: exSets,
      reps: exReps,
      setsReps: exSets + ' x ' + exReps,
      day: day.day,
      muscle: day.muscle || '',
      ytQuery: (exName + ' ' + context).replace(/\s+/g, ' ').trim(),
      workoutJson: data.workoutJson,
      clientId: data.clientId,
      clientName: data.clientName,
      clientEmail: data.clientEmail,
      clientPhone: data.clientPhone,
      planType: data.planType,
      goal: data.goal,
      isDiet: false
    }});
  }
}
return items;

const geminiResp = $input.first().json || {};
const prev = $('Build Gemini Prompt').first().json;

function cleanText(value) {
  return String(value || '')
    .replace(/^\`\`\`json\s*/i, '')
    .replace(/^\`\`\`\s*/i, '')
    .replace(/\`\`\`\s*$/i, '')
    .trim();
}

function parseDays(value) {
  const match = String(value || '').match(/\d+/);
  return Math.max(3, Math.min(6, Number(match ? match[0] : 5)));
}

function workoutExercises(prev) {
  const bodyweight = String(prev.gymAccess || '').toLowerCase().includes('bodyweight');
  if (bodyweight) {
    return {
      push: [
        { name: 'Push-Up', sets: '4', reps: '8-15' },
        { name: 'Pike Push-Up', sets: '3', reps: '8-12' },
        { name: 'Bench Dip', sets: '3', reps: '10-15' },
        { name: 'Plank Shoulder Tap', sets: '3', reps: '20' }
      ],
      pull: [
        { name: 'Inverted Row', sets: '4', reps: '8-12' },
        { name: 'Superman Pull', sets: '3', reps: '12-15' },
        { name: 'Reverse Snow Angel', sets: '3', reps: '12-15' },
        { name: 'Towel Curl', sets: '3', reps: '10-12' }
      ],
      legs: [
        { name: 'Bodyweight Squat', sets: '4', reps: '15-20' },
        { name: 'Reverse Lunge', sets: '3', reps: '10-12 each' },
        { name: 'Glute Bridge', sets: '3', reps: '12-15' },
        { name: 'Standing Calf Raise', sets: '4', reps: '15-20' }
      ],
      core: [
        { name: 'Plank', sets: '3', reps: '45 sec' },
        { name: 'Dead Bug', sets: '3', reps: '10 each' },
        { name: 'Mountain Climber', sets: '3', reps: '30 sec' },
        { name: 'Side Plank', sets: '3', reps: '30 sec each' }
      ]
    };
  }
  return {
    push: [
      { name: 'Barbell Bench Press', sets: '4', reps: '8-10' },
      { name: 'Incline Dumbbell Press', sets: '3', reps: '10-12' },
      { name: 'Cable Fly', sets: '3', reps: '12-15' },
      { name: 'Triceps Pushdown', sets: '3', reps: '10-12' }
    ],
    pull: [
      { name: 'Lat Pulldown', sets: '4', reps: '10-12' },
      { name: 'Seated Cable Row', sets: '3', reps: '10-12' },
      { name: 'Face Pull', sets: '3', reps: '12-15' },
      { name: 'Dumbbell Curl', sets: '3', reps: '10-12' }
    ],
    legs: [
      { name: 'Back Squat', sets: '4', reps: '8-10' },
      { name: 'Romanian Deadlift', sets: '3', reps: '10-12' },
      { name: 'Leg Press', sets: '3', reps: '12-15' },
      { name: 'Standing Calf Raise', sets: '4', reps: '12-15' }
    ],
    core: [
      { name: 'Overhead Press', sets: '4', reps: '8-10' },
      { name: 'Lateral Raise', sets: '3', reps: '12-15' },
      { name: 'Cable Crunch', sets: '3', reps: '12-15' },
      { name: 'Plank', sets: '3', reps: '45 sec' }
    ]
  };
}

function fallbackWorkout(prev) {
  const available = parseDays(prev.daysPerWeek);
  const days = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday', 'Sunday'];
  const split = [
    ['Push Strength', 'push'],
    ['Pull Strength', 'pull'],
    ['Legs', 'legs'],
    ['Shoulders & Core', 'core'],
    ['Upper Body Volume', 'push'],
    ['Posterior Chain', 'pull']
  ];
  const library = workoutExercises(prev);
  return {
    greeting: 'Hi ' + (prev.clientName || 'there') + '! Your one-week AirFit training template is ready.',
    overview: 'This one-week template is built around your goal, equipment, and available training days. Repeat the same template across the month while AirFit tracks each calendar repeat separately.',
    days: days.map((day, index) => {
      if (index >= available) return { day, muscle: 'Rest', exercises: [] };
      const [muscle, key] = split[index];
      return { day, muscle, exercises: library[key] };
    }),
    warmup: ['5 min light cardio', 'Dynamic mobility', 'Ramp-up sets before heavy lifts'],
    cooldown: ['Static stretch 30s per target muscle', 'Deep breathing 2 min'],
    recoveryTips: ['Sleep 7-9 hours', 'Stay hydrated', 'Repeat this template weekly for 4 weeks']
  };
}

function fallbackDiet(prev) {
  const name = prev.clientName || 'there';
  const goal = prev.goal || 'your fitness goal';
  return '<p>Hi ' + name + '!</p>'
    + '<h2 style="color:#ff6b00">Personalised Diet Plan - ' + goal + '</h2>'
    + '<h3 style="color:#ff6b00">1. Daily Calorie Target and Macros</h3>'
    + '<p style="color:#e0e0e0">Use this safe starter plan while the AI service is unavailable. Keep protein high, choose mostly whole foods, and adjust portions based on weekly progress.</p>'
    + '<ul style="color:#e0e0e0"><li><strong>Protein:</strong> 1.6-2.2g per kg bodyweight</li><li><strong>Carbohydrates:</strong> focus on rice, oats, potatoes, fruit, and whole grains</li><li><strong>Fats:</strong> nuts, olive oil, eggs, fish, and dairy as tolerated</li></ul>'
    + '<h3 style="color:#ff6b00">2. 7-Day Meal Plan</h3>'
    + '<p style="color:#e0e0e0">Build each day around breakfast, lunch, snack, dinner, and hydration. Regenerate once the AI key is restored for a fully personalised version.</p>';
}

const candidateText = geminiResp.candidates?.[0]?.content?.parts?.[0]?.text;
let rawText = cleanText(candidateText);
const aiFailed = !rawText || geminiResp.error || geminiResp.statusCode >= 400 || geminiResp.httpCode >= 400;

if (prev.isDiet) {
  return [{ json: {
    isDiet: true,
    planHtml: aiFailed ? fallbackDiet(prev) : rawText,
    workoutJson: null,
    aiFallbackUsed: Boolean(aiFailed),
    clientId: prev.clientId, clientName: prev.clientName,
    clientEmail: prev.clientEmail, clientPhone: prev.clientPhone,
    planType: prev.planType, goal: prev.goal
  }}];
}

let workoutJson = null;
if (!aiFailed) {
  try { workoutJson = JSON.parse(rawText); }
  catch(e) {
    const m = rawText.match(/\{[\s\S]*\}/);
    if (m) { try { workoutJson = JSON.parse(m[0]); } catch(e2) {} }
  }
}
if (!workoutJson || !Array.isArray(workoutJson.days) || workoutJson.days.length !== 7) {
  workoutJson = fallbackWorkout(prev);
}
return [{ json: {
  isDiet: false, planHtml: null, workoutJson,
  aiFallbackUsed: Boolean(aiFailed),
  clientId: prev.clientId, clientName: prev.clientName,
  clientEmail: prev.clientEmail, clientPhone: prev.clientPhone,
  planType: prev.planType, goal: prev.goal
}}];

const raw = $('Webhook Trigger').first().json;
let body;
if (typeof raw.body === 'string') {
  try { body = JSON.parse(raw.body); } catch(e) { body = raw.body; }
} else {
  body = raw.body || raw;
}

const planType = body.planType || 'Workout Plan';
const isDiet   = planType.toLowerCase().includes('diet');
const daysRequested = String(body.daysPerWeek || '5 days');
let prompt;

if (isDiet) {
  prompt = 'Expert fitness coach at Airfit Gym. Create personalised Diet Plan.\n\n'
    + 'CLIENT: ' + body.name + ' | ' + body.gender + ' | ' + body.age + 'yrs | '
    + body.height + 'cm | ' + body.weight + 'kg | Goal: ' + body.goal + '\n'
    + 'Activity: ' + body.activityLevel + ' | Diet: ' + body.dietPreference
    + ' | Food: ' + body.foodCulture + ' | Meals: ' + body.mealsPerDay
    + ' | History: ' + body.previousWorkout + ' | Allergies: ' + (body.allergies || 'None') + '\n\n'
    + 'Create a concise DIET PLAN:\n1. Daily calorie target and macros\n'
    + '2. 7-day meal plan table (Day|Breakfast|Lunch|Dinner|Snacks)\n'
    + '3. Pre/post workout meals\n4. Hydration\n5. Top 5 foods to avoid\n6. 3 supplements\n'
    + 'NO YouTube links.\n\nOUTPUT: raw HTML only, inline CSS, headings color:#ff6b00, '
    + 'tables border-collapse rows #1a1a1a/#222 text #e0e0e0, '
    + 'headers bg #ff6b00 white padding:10px, cells padding:10px border-bottom:1px solid #333. '
    + 'Start: <p>Hi ' + body.name + '!</p>';
} else {
  prompt = 'You are an expert fitness coach at Airfit Gym. Build ONE reusable 7-day workout template for this client.\n\n'
    + 'CLIENT: ' + body.name + ' | ' + body.gender + ' | ' + body.age + 'yrs | '
    + body.height + 'cm | ' + body.weight + 'kg | Goal: ' + body.goal + '\n'
    + 'Activity: ' + body.activityLevel + ' | History: ' + (body.previousWorkout || 'Beginner') + '\n'
    + 'Gym Access: ' + (body.gymAccess || 'Full Gym') + ' | Days Available: ' + daysRequested + ' | Session: ' + (body.sessionLength || '45-60 min') + '\n'
    + 'Focus: ' + (body.focusArea || 'Full Body') + ' | Injuries/Limitations: ' + (body.injuries || 'None') + '\n\n'
    + 'Return ONLY a valid JSON object. No markdown. No explanation. No code fences.\n\n'
    + 'Required format:\n'
    + '{"greeting":"Hi ' + body.name + '! [motivating sentence]",'
    + '"overview":"[2 sentence overview explaining this one-week template repeats for the month]",'
    + '"days":[{"day":"Monday","muscle":"Chest & Triceps","exercises":['
    + '{"name":"Barbell Bench Press","sets":"4","reps":"8-10"}'
    + ']}],'
    + '"warmup":["5 min light cardio","Dynamic mobility"],'
    + '"cooldown":["Static stretch 30s","Deep breathing"],'
    + '"recoveryTips":["Sleep 7-9 hours","Stay hydrated","Repeat this template weekly for 4 weeks"]}\n\n'
    + 'STRICT RULES:\n'
    + '- Exactly 7 day objects: Monday, Tuesday, Wednesday, Thursday, Friday, Saturday, Sunday.\n'
    + '- Use the client Days Available to decide how many workout days; rest days must have "muscle":"Rest" and "exercises": [].\n'
    + '- Workout days must have 4-6 exercises tailored to goal, equipment, experience, focus area, and injuries.\n'
    + '- Each exercise must have accurate "name", "sets", and "reps" as strings.\n'
    + '- Do not include video IDs or links; the workflow will attach short YouTube demos.\n'
    + '- Output ONLY the JSON. Nothing else.';
}

return [{ json: {
  geminiPayload: JSON.stringify({
    contents: [{ parts: [{ text: prompt }] }],
    generationConfig: { temperature: 0.65, maxOutputTokens: 4096 }
  }),
  clientId:    body.clientId   || '',
  clientName:  body.name       || '',
  clientEmail: body.email      || '',
  clientPhone: body.phone      || '',
  age:         body.age        || '',
  gender:      body.gender     || '',
  planType:    planType,
  isDiet:      isDiet,
  goal:        body.goal       || '',
  gymAccess:   body.gymAccess  || 'Full Gym',
  focusArea:   body.focusArea  || '',
  injuries:    body.injuries   || '',
  daysPerWeek: daysRequested,
  sessionLength: body.sessionLength || ''
}}];

const items = $input.all();
const exItems = $('Extract Exercises').all();
const clientCtx = $('Build Gemini Prompt').first().json;
const out = [];

for (let i = 0; i < items.length; i++) {
  const cur = items[i].json;
  // Fallback to finding the matching exercise by item index, or just assuming 1:1 if handled individually.
  // Since HTTP node processes items sequentially, we can map them directly:
  const exCtx = exItems[i].json;

  const fields = cur.fields || {};
  const videoId = fields.videoId?.stringValue || null;
  const videoUrl = fields.url?.stringValue || null;
  const thumb = fields.thumb?.stringValue || null;

  out.push({ json: {
    exerciseMode: true,
    exerciseName: exCtx.exerciseName || '',
    sets: exCtx.sets || '3',
    reps: exCtx.reps || '10',
    setsReps: exCtx.setsReps || '3 x 10',
    day: exCtx.day || '',
    muscle: exCtx.muscle || '',
    videoId,
    videoUrl,
    videoTitle: fields.name?.stringValue || exCtx.exerciseName,
    channelName: 'Airfit Curated',
    durationSeconds: 30,
    isShortCandidate: true,
    isPreferredShort: true,
    videoFallback: false,
    videoSearchQuery: '',
    thumb,
    workoutJson: exCtx.workoutJson || null,
    clientId: clientCtx.clientId,
    clientName: clientCtx.clientName,
    clientEmail: clientCtx.clientEmail,
    clientPhone: clientCtx.clientPhone,
    planType: clientCtx.planType,
    goal: clientCtx.goal,
    isDiet: false
  }});
}
return out;
